import { FC, memo, useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Deck } from '@/types';
import { useNotificationStore } from '@/store/notificationStore';
import { usePinnedDecksStore } from '@/store/pinnedDecksStore';
import { hasTranscriptsForDeck } from '@/services/transcriptService';
import {
  FlashcardsIcon,
  LearnIcon,
  MatchIcon,
  ReadIcon,
  CardsIcon,
  LevelsIcon,
  ClockIcon,
} from '@/components/icons/ModeIcons';
import { PinIcon, PinFilledIcon } from '@/components/icons/PinIcon';
import styles from './EnhancedDeckCard.module.css';

interface ModeConfig {
  id: 'flashcards' | 'learn' | 'match' | 'read';
  label: string;
  icon: FC<{ className?: string }>;
  color: string;
  description: string;
  route: string;
}

interface DeckProgress {
  overall: number;
  byMode: Record<string, number>;
  lastStudied?: Date;
  totalCardsStudied: number;
  streakDays: number;
  masteredCards: number;
  totalCards: number;
}

interface EnhancedDeckCardProps {
  deck: Deck;
  progress?: DeckProgress;
  onModeSelect?: (deckId: string, mode: string) => void;
}

const formatLastStudied = (date?: Date): string => {
  if (!date) return 'Never';

  const now = new Date();
  const diff = now.getTime() - date.getTime();
  const days = Math.floor(diff / (1000 * 60 * 60 * 24));

  if (days === 0) return 'Today';
  if (days === 1) return 'Yesterday';
  if (days < 7) return `${days} days ago`;
  if (days < 30) return `${Math.floor(days / 7)} weeks ago`;
  return `${Math.floor(days / 30)} months ago`;
};

// Memoized SVG progress ring to avoid recalculations
const CircularProgress: FC<{ value: number }> = memo(({ value }) => {
  const radius = 16;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (value / 100) * circumference;

  return (
    <svg viewBox="0 0 40 40" className={styles.progressSvg}>
      <circle
        cx="20"
        cy="20"
        r={radius}
        className={styles.progressBackground}
        strokeWidth="2.5"
        fill="none"
      />
      <circle
        cx="20"
        cy="20"
        r={radius}
        className={styles.progressFill}
        strokeWidth="2.5"
        fill="none"
        strokeDasharray={circumference}
        strokeDashoffset={offset}
        strokeLinecap="round"
      />
      <text x="20" y="20" className={styles.progressText} textAnchor="middle" dy="0.3em">
        {Math.round(value)}%
      </text>
    </svg>
  );
});
CircularProgress.displayName = 'CircularProgress';

const DifficultyBadge: FC<{ level?: string }> = ({ level }) => {
  if (!level) return null;

  return (
    <span className={`${styles.difficultyBadge} ${styles[level.replace('_', '-')]}`}>
      {level.replace('_', ' ')}
    </span>
  );
};

export const EnhancedDeckCard: FC<EnhancedDeckCardProps> = memo(
  ({
    deck,
    progress = {
      overall: 0,
      byMode: {},
      totalCardsStudied: 0,
      streakDays: 0,
      masteredCards: 0,
      totalCards: deck.content.length,
    },
    onModeSelect,
  }) => {
    const [hasTranscripts, setHasTranscripts] = useState(false);
    const navigate = useNavigate();
    const { showNotification } = useNotificationStore();
    const pinned = usePinnedDecksStore(state => state.pinnedDeckIds.includes(deck.id));
    const togglePin = usePinnedDecksStore(state => state.togglePin);
    const { metadata } = deck;

    // Check for transcripts availability
    useEffect(() => {
      hasTranscriptsForDeck(deck.id).then(setHasTranscripts);
    }, [deck.id]);

    const modes: ModeConfig[] = [
      {
        id: 'flashcards',
        label: 'Flashcards',
        icon: FlashcardsIcon,
        color: 'primary',
        description: 'Classic flip cards',
        route: `/flashcards/${deck.id}`,
      },
      {
        id: 'learn',
        label: 'Learn',
        icon: LearnIcon,
        color: 'secondary',
        description: 'Interactive questions',
        route: `/learn/${deck.id}`,
      },
      {
        id: 'match',
        label: 'Match',
        icon: MatchIcon,
        color: 'purple',
        description: 'Memory game',
        route: `/match/${deck.id}`,
      },
      {
        id: 'read',
        label: 'Read',
        icon: ReadIcon,
        color: 'orange',
        description: 'Structured reading practice',
        route: `/read/${deck.id}`,
      },
    ];

    const handleModeClick = (e: React.MouseEvent, mode: ModeConfig) => {
      e.stopPropagation();

      // Check if Read mode is available for this deck
      if (mode.id === 'read') {
        const hasReadingContent = deck.reading && Object.keys(deck.reading.dialogues).length > 0;
        if (!hasReadingContent && !hasTranscripts) {
          showNotification({
            message: 'No reading content available for this deck',
            type: 'info',
            duration: 3000,
          });
          return;
        }
      }

      onModeSelect?.(deck.id, mode.id);
      navigate(mode.route);
    };

    const handleCardClick = () => {
      navigate(`/deck/${deck.id}`);
    };

    const handlePinClick = (e: React.MouseEvent) => {
      e.stopPropagation();
      togglePin(deck.id);
    };

    return (
      <article
        className={styles.enhancedDeckCard}
        onClick={handleCardClick}
      >
        <button
          type="button"
          className={`${styles.pinButton} ${pinned ? styles.pinned : ''}`}
          onClick={handlePinClick}
          aria-label={pinned ? 'Unpin deck' : 'Pin deck'}
          aria-pressed={pinned}
        >
          {pinned ? <PinFilledIcon size={18} /> : <PinIcon size={18} />}
        </button>

        {/* Progress Ring - Shows mastery percentage of entire deck */}
        {progress.overall > 0 && (
          <div className={styles.progressRing}>
            <CircularProgress value={progress.overall} />
          </div>
        )}

        {/* Deck Info */}
        <header className={styles.cardHeader}>
          <h3 className={styles.deckName}>{metadata.deck_name}</h3>
          <DifficultyBadge level={metadata.difficulty} />
        </header>

        {metadata.deck_subtitle && <p className={styles.subtitle}>{metadata.deck_subtitle}</p>}

        {metadata.description && <p className={styles.description}>{metadata.description}</p>}

        <div className={styles.stats}>
          <div className={styles.statItem}>
            <CardsIcon className={styles.statIcon} size={16} />
            <span className={styles.statValue}>
              {progress.masteredCards > 0
                ? `${progress.masteredCards}/${metadata.card_count || deck.content.length}`
                : metadata.card_count || deck.content.length}
            </span>
            <span className={styles.statLabel}>
              {progress.masteredCards > 0 ? 'mastered' : 'cards'}
            </span>
          </div>

          {metadata.available_levels && metadata.available_levels.length > 0 && (
            <div className={styles.statItem}>
              <LevelsIcon className={styles.statIcon} size={16} />
              <span className={styles.statValue}>{metadata.available_levels.length}</span>
              <span className={styles.statLabel}>levels</span>
            </div>
          )}

          {(hasTranscripts || (deck.reading && Object.keys(deck.reading.dialogues).length > 0)) && (
            <div className={styles.statItem}>
              <ReadIcon className={styles.statIcon} size={16} />
              <span className={styles.statLabel}>reading</span>
            </div>
          )}

          <div className={styles.statItem}>
            <ClockIcon className={styles.statIcon} size={16} />
            <span className={styles.statValue}>{formatLastStudied(progress.lastStudied)}</span>
          </div>
        </div>

        {/* Tags */}
        {metadata.tags && metadata.tags.length > 0 && (
          <div className={styles.tags}>
            {metadata.tags.slice(0, 3).map(tag => (
              <span key={tag} className={styles.tag}>
                {tag}
              </span>
            ))}
            {metadata.tags.length > 3 && (
              <span className={styles.tag}>+{metadata.tags.length - 3}</span>
            )}
          </div>
        )}

        {/* Mode Selection Strip */}
        <div className={styles.modeStrip}>
          {modes.map(mode => (
            <button
              key={mode.id}
              className={`${styles.modeButton} ${styles[mode.id]}`}
              onClick={e => handleModeClick(e, mode)}
              aria-label={`Study ${metadata.deck_name} with ${mode.label} mode`}
              title={mode.description}
            >
              <mode.icon className={styles.modeIcon} />
              <span className={styles.modeLabel}>{mode.label}</span>
            </button>
          ))}
        </div>
      </article>
    );
  }
);

EnhancedDeckCard.displayName = 'EnhancedDeckCard';

export default EnhancedDeckCard;
